   421→
   422→  describe('addSessionWarning', () => {
   423→    it('should add warning with default low impact', () => {
   424→      const session = createClassificationSession(mockConfig);
   425→
   426→      addSessionWarning(session, 'email-123', 'disambiguation', 'Close scores detected');
   427→
   428→      expect(session.warnings).toHaveLength(1);
   429→      expect(session.warnings[0]).toMatchObject({
   430→        emailId: 'email-123',
   431→        stage: 'disambiguation',
   432→        warning: 'Close scores detected',
