   146→  [category: string]: {
   147→    hard_include: string[];
   148→    hard_exclude: string[];
   149→    strong_include: string[];
   150→    strong_exclude: string[];
   151→  };
   152→}
   153→
   154→/**
   155→ * Domain resolution configuration
   156→ */
