   158→  mode: string; // "runtime_resolved"
   159→  source: string; // "config/domain-sources.json"
   160→  notes: string;
   161→}
   162→
   163→/**
   164→ * Top-level category definition with subtypes and AI classification
   165→ */
   166→export interface TopLevelCategory {
   167→  description: string;
   168→  subtypes: Record<string, SubtypeDefinition>;
   169→  ai_final_classification: {
   170→    category_description: string;
