   199→
   200→/**
   201→ * Attribute system configuration
   202→ */
   203→export interface AttributeSystem {
   204→  schema: Record<string, AttributeSchema>;
   205→  detectors: AttributeDetector[];
   206→  derived: Record<string, DerivedAttribute>;
   207→  attribute_bonus_map: Record<string, Record<string, number>>;
   208→}
   209→
