   212→  values?: string[]; // For enum types
   213→  description: string;
   214→}
   215→
   216→export interface AttributeDetector {
   217→  attribute: string;
   218→  field: string;
   219→  operation: string;
   220→  values: string[];
   221→}
   222→
   223→export interface DerivedAttribute {
   224→  logic: string;
   225→  notes: string;
   226→}
   227→
   228→/**
   229→ * Attribute relevance matrix implementing roles from SCORING_LOGIC.md
   230→ */
   231→export interface AttributeRelevanceMatrix {
