import { executeStrongIndicators, StrongIndicatorStageConfig } from '../../src/stages/strong-indicators';
import {
  EmailMessage,
  ProcessingConfig,
  ProcessingSettings,
  MultiLabelPolicy,
  DomainOverrides,
  DomainResolution,
  AttributeSystem,
  AttributeRelevanceMatrix,
  AIPromptSystem,
  JSONSchema,
} from '../../src/types';
import { createClassificationSession, createClassificationResult } from '../../src/utils/initialization';

describe('Strong Indicators Stage', () => {
  const mockConfig: StrongIndicatorStageConfig = {
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.2,
      secondaryLabelMinGap: 0.1,
    },
    categorySignals: {
      Financial: {
        strong_indicators: {
          from_domains_ref: {
            source_group: 'banking_domains',
            confidence: 'high',
          },
          subject_contains: ['payment', 'transaction', 'balance'],
          body_contains: ['account', 'credit card', 'statement'],
        },
      },
      Shopping: {
        strong_indicators: {
          subject_contains: ['order', 'shipping', 'receipt'],
          body_contains: ['purchase', 'delivery'],
        },
      },
    },
    domainLookup: {
      banking_domains: {
        high_confidence: [
          { domain: 'chase.com', type: 'bank' },
          { domain: 'bankofamerica.com', type: 'bank' },
        ],
        medium_confidence: [{ domain: 'paypal.com', type: 'payment' }],
        low_confidence: [],
      },
    },
    strongIndicatorBaseWeight: 10,
    diminishingReturnsFactor: 0.5,
  };

  const createMockEmail = (overrides: Partial<EmailMessage> = {}): EmailMessage => ({
    id: 'test-email-id',
    threadId: 'test-thread-id',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [],
    },
    subject: 'Test Subject',
    from: { email: 'test@example.com', raw: 'test@example.com' },
    to: [{ email: 'recipient@example.com', raw: 'recipient@example.com' }],
    date: new Date(),
    isProcessed: false,
    processingPriority: 1,
    bodyPlain: 'Test body content',
    ...overrides,
  });

  const createMockProcessingConfig = (): ProcessingConfig => {
    const settings: ProcessingSettings = {
      initialization: {
        apply_hard_assertions: true,
        seed_category_scores: true,
      },
      rule_scoring: {
        use_lexical_patterns: true,
        apply_subtype_rules: true,
        bounded_aggregation: true,
      },
      attribute_processing: {
        detect_self_sent: true,
        resolve_domains: true,
        derive_context_flags: true,
      },
      attribute_influence: {
        apply_bonuses: true,
        apply_penalties: true,
        enforce_caps: true,
      },
      multi_label_selection: {
        max_labels: 3,
        min_secondary_confidence: 0.5,
        allowed_combinations: [],
      },
      ai_routing: {
        high_confidence_threshold: 0.8,
        ai_required_threshold: 0.3,
        skip_ai_conditions: [],
      },
    };

    const multiLabelPolicy: MultiLabelPolicy = {
      max_top_level_labels: 3,
      min_confidence_for_additional: 0.5,
      min_delta_primary_secondary: 0.2,
      allow_financial_actionable_copresence: true,
    };

    const domainOverrides: DomainOverrides = {};

    const domainResolution: DomainResolution = {
      mode: 'runtime_resolved',
      source: 'config/domain-sources.json',
      notes: 'Test config',
    };

    const attributes: AttributeSystem = {
      schema: {},
      detectors: [],
      derived: {},
      attribute_bonus_map: {},
    };

    const attributeRelevance: AttributeRelevanceMatrix = {
      _roles_legend: {
        CORE: 'Core attribute',
        PRIMARY_BOOST: 'Primary boost',
        SECONDARY_BOOST: 'Secondary boost',
        DISAMBIGUATOR: 'Disambiguator',
        FILTER: 'Filter',
        STRUCTURAL: 'Structural',
        DERIVED_LINK: 'Derived link',
        NEUTRAL: 'Neutral',
      },
    };

    const aiPrompts: AIPromptSystem = {
      feature_extraction: {
        system_prompt: ['Extract features'],
        user_prompt: ['Analyze email'],
      },
      final_classification: {
        system_prompt: ['Classify email'],
        user_prompt: ['Determine category'],
      },
    };

    const featureExtractionSchema: JSONSchema = {
      type: 'object',
      properties: {},
      required: [],
    };

    return {
      version: 1,
      taxonomy_notes: '',
      settings,
      category_signals: {},
      confidence_thresholds: mockConfig.confidenceThresholds,
      multi_label_policy: multiLabelPolicy,
      domain_signal_overrides: domainOverrides,
      domain_signal_resolution: domainResolution,
      top_level_categories: {},
      attributes,
      attribute_relevance: attributeRelevance,
      ai_prompts: aiPrompts,
      feature_extraction_schema: featureExtractionSchema,
    };
  };

  // Helper to set up test with initial scores and seeds
  const setupTest = (initialScores: Record<string, number> = {}, existingSeeds: Record<string, number> = {}) => {
    const processingConfig = createMockProcessingConfig();
    const session = createClassificationSession(processingConfig, 'sequential', 1);
    const email = createMockEmail();
    const result = createClassificationResult(email.id, session.id, 0);

    // Initialize scores
    for (const [category, score] of Object.entries(initialScores)) {
      result.scoreBreakdown.categoryScores[category] = {
        baseScore: score,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: score,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };
    }

    // Initialize strong indicator seeds
    for (const [category, seed] of Object.entries(existingSeeds)) {
      if (!result.scoreBreakdown.categoryScores[category]) {
        result.scoreBreakdown.categoryScores[category] = {
          baseScore: 0,
          hardAssertionBonus: 0,
          strongIndicatorScore: 0,
          ruleScore: 0,
          attributeInfluenceScore: 0,
          finalScore: 0,
          parallelComputedComponents: [],
          computationDurationMs: 0,
          cacheHits: [],
          scoreAggregationSteps: [],
          cappingApplied: false,
        };
      }
      result.scoreBreakdown.categoryScores[category].strongIndicatorScore = seed;
    }

    return { email, session, result };
  };

  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('from_domains_ref indicators', () => {
    it('should apply strong indicator for matching high-confidence domain', () => {
      const { session, result } = setupTest({ Financial: 0.1, Shopping: 0.2 });
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
      expect(result.explainabilityTrace.strongIndicators[0]).toMatchObject({
        category: 'Financial',
        indicatorType: 'from_domain',
        matchedValue: 'chase.com',
        seedScore: 10,
        diminishingReturnsApplied: false,
        existingSeedScore: 0,
        finalSeedScore: 10,
      });
      expect(result.scoreBreakdown.categoryScores.Financial.strongIndicatorScore).toBe(10);
    });

    it('should apply strong indicator for matching medium-confidence domain', () => {
      // Create a config with medium confidence setting
      const mediumConfConfig: StrongIndicatorStageConfig = {
        ...mockConfig,
        categorySignals: {
          Financial: {
            strong_indicators: {
              from_domains_ref: {
                source_group: 'banking_domains',
                confidence: 'medium', // Changed to medium to match paypal.com
              },
            },
          },
        },
      };

      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        from: { email: 'user@paypal.com', raw: 'user@paypal.com' },
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mediumConfConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
      expect(result.scoreBreakdown.categoryScores.Financial.strongIndicatorScore).toBe(10);
      expect(result.explainabilityTrace.strongIndicators[0].matchedValue).toBe('paypal.com');
    });

    it('should not apply indicator for non-matching domain', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        from: { email: 'user@random.com', raw: 'user@random.com' },
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(0);
      expect(result.scoreBreakdown.categoryScores.Financial.strongIndicatorScore).toBe(0);
    });
  });

  describe('subject_contains indicators', () => {
    it('should apply strong indicator for matching subject keywords', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: 'Your monthly payment statement is ready',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
      expect(result.scoreBreakdown.categoryScores.Financial.strongIndicatorScore).toBe(10);
      expect(result.explainabilityTrace.strongIndicators[0]).toMatchObject({
        category: 'Financial',
        indicatorType: 'subject_contains',
        matchedValue: 'payment',
        seedScore: 10,
        diminishingReturnsApplied: false,
      });
    });

    it('should apply diminishing returns for multiple subject matches', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: 'Payment transaction completed for your balance',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(3); // payment, transaction, balance

      // First match gets full weight
      expect(result.explainabilityTrace.strongIndicators[0].seedScore).toBe(10);
      expect(result.explainabilityTrace.strongIndicators[0].diminishingReturnsApplied).toBe(false);

      // Subsequent matches get diminished weight
      expect(result.explainabilityTrace.strongIndicators[1].seedScore).toBe(5); // 10 * 0.5
      expect(result.explainabilityTrace.strongIndicators[1].diminishingReturnsApplied).toBe(true);

      expect(result.explainabilityTrace.strongIndicators[2].seedScore).toBe(5); // 10 * 0.5
      expect(result.explainabilityTrace.strongIndicators[2].diminishingReturnsApplied).toBe(true);
    });

    it('should handle case-insensitive subject matching', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: 'PAYMENT NOTIFICATION',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
      expect(result.explainabilityTrace.strongIndicators[0].matchedValue).toBe('payment');
    });
  });

  describe('body_contains indicators', () => {
    it('should apply strong indicator for matching body keywords', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        bodyPlain: 'Your account balance has been updated. Please review your credit card statement.',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(3); // account, credit card, statement

      // Check diminishing returns applied
      expect(result.explainabilityTrace.strongIndicators[0].seedScore).toBe(10); // First match
      expect(result.explainabilityTrace.strongIndicators[1].seedScore).toBe(5); // Diminished
      expect(result.explainabilityTrace.strongIndicators[2].seedScore).toBe(5); // Diminished
    });

    it('should extract text from HTML body when plain text not available', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        bodyPlain: undefined,
        bodyHtml: '<html><body><p>Your <strong>account</strong> statement is ready.</p></body></html>',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(2); // account, statement
      expect(result.explainabilityTrace.strongIndicators[0].matchedValue).toBe('account');
    });

    it('should prefer plain text over HTML when both available', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        bodyPlain: 'Plain text with account info',
        bodyHtml: '<html><body>HTML with different keywords</body></html>',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
      expect(result.explainabilityTrace.strongIndicators[0].matchedValue).toBe('account');
    });
  });

  describe('multiple categories and cross-dimension matching', () => {
    it('should handle indicators across multiple categories', () => {
      const { session, result } = setupTest({ Shopping: 0.1 });
      const email = createMockEmail({
        subject: 'Order confirmation for your purchase',
        bodyPlain: 'Thank you for your purchase. Your order will be shipped soon.',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.scoreBreakdown.categoryScores.Shopping.strongIndicatorScore).toBeGreaterThan(0);

      // Should have matches from both subject and body
      const shoppingResults = result.explainabilityTrace.strongIndicators.filter((r) => r.category === 'Shopping');
      expect(shoppingResults.length).toBeGreaterThan(1);
    });

    it('should track different dimensions separately for diminishing returns', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: 'Payment due for transaction', // 2 matches: payment, transaction
        bodyPlain: 'Your account and credit card statement', // 3 matches: account, credit card, statement
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      const subjectResults = result.explainabilityTrace.strongIndicators.filter(
        (r) => r.indicatorType === 'subject_contains'
      );
      const bodyResults = result.explainabilityTrace.strongIndicators.filter(
        (r) => r.indicatorType === 'body_contains'
      );

      // Each dimension should have its own diminishing returns
      expect(subjectResults[0].seedScore).toBe(10); // First subject match
      expect(subjectResults[1].seedScore).toBe(5); // Second subject match (diminished)

      expect(bodyResults[0].seedScore).toBe(10); // First body match (new dimension)
      expect(bodyResults[1].seedScore).toBe(5); // Second body match (diminished)
    });
  });

  describe('seed score management with max logic', () => {
    it('should use max logic when combining with existing seeds', () => {
      const { session, result } = setupTest({ Financial: 0.1 }, { Financial: 15 });
      const email = createMockEmail({
        subject: 'Payment notification',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.scoreBreakdown.categoryScores.Financial.strongIndicatorScore).toBe(25); // 15 (existing) + 10 (new) = 25
      expect(result.explainabilityTrace.strongIndicators[0].finalSeedScore).toBe(25);
    });

    it('should update seed when new calculated seed is higher', () => {
      const { session, result } = setupTest({ Financial: 0.1 }, { Financial: 5 });
      const email = createMockEmail({
        subject: 'Payment transaction balance', // Multiple matches = higher total
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      // Should update to higher calculated seed (5 + 10 + 5 + 5 = 25)
      expect(result.scoreBreakdown.categoryScores.Financial.strongIndicatorScore).toBeGreaterThan(5);
    });

    it('should accumulate within same processing correctly', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: 'Payment for transaction',
        bodyPlain: 'Account statement available',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      // Should accumulate: payment(10) + transaction(5) + account(10) + statement(5) = 30
      expect(result.scoreBreakdown.categoryScores.Financial.strongIndicatorScore).toBe(30);
    });
  });

  describe('context tracking and performance', () => {
    it('should track processing duration and update result', () => {
      const { session, result } = setupTest({});
      const email = createMockEmail();
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      expect(result.explainabilityTrace.stageTimings.strong_indicators).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.configurationRefs.strong_indicators).toBe(
        'category_signals.*.strong_indicators'
      );
    });

    it('should handle empty configuration gracefully', () => {
      const { session, result } = setupTest({ Financial: 0.1, Shopping: 0.2 });
      const email = createMockEmail();
      result.emailId = email.id;
      const emptyConfig: StrongIndicatorStageConfig = {
        ...mockConfig,
        categorySignals: {},
      };

      executeStrongIndicators(email, session, result, emptyConfig);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(0);
      expect(result.explainabilityTrace.stageTimings.strong_indicators).toBeGreaterThanOrEqual(0);
    });
  });

  describe('edge cases', () => {
    it('should handle missing domain lookup gracefully', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
      });
      result.emailId = email.id;
      const configWithMissingDomains: StrongIndicatorStageConfig = {
        ...mockConfig,
        domainLookup: {}, // Missing banking_domains
      };

      executeStrongIndicators(email, session, result, configWithMissingDomains);

      expect(result.explainabilityTrace.strongIndicators).toHaveLength(0);
    });

    it('should handle missing email body gracefully', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        bodyPlain: undefined,
        bodyHtml: undefined,
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      // Should only process subject_contains, not body_contains
      const bodyResults = result.explainabilityTrace.strongIndicators.filter(
        (r) => r.indicatorType === 'body_contains'
      );
      expect(bodyResults).toHaveLength(0);
    });

    it('should handle empty subject gracefully', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: '',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, mockConfig);

      const subjectResults = result.explainabilityTrace.strongIndicators.filter(
        (r) => r.indicatorType === 'subject_contains'
      );
      expect(subjectResults).toHaveLength(0);
    });

    it('should apply configured weights and diminishing factor', () => {
      const customConfig: StrongIndicatorStageConfig = {
        ...mockConfig,
        strongIndicatorBaseWeight: 15,
        diminishingReturnsFactor: 0.3,
      };

      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: 'Payment transaction notification',
      });
      result.emailId = email.id;

      executeStrongIndicators(email, session, result, customConfig);

      expect(result.explainabilityTrace.strongIndicators[0].seedScore).toBe(15); // Custom base weight
      expect(result.explainabilityTrace.strongIndicators[1].seedScore).toBe(4.5); // 15 * 0.3
    });
  });
});

