import { executeHardAssertions, HardAssertionStageConfig } from '../../src/stages/hard-assertions';
import { EmailMessage, ProcessingConfig } from '../../src/types';
import { createClassificationSession, createClassificationResult } from '../../src/utils/initialization';

describe('Hard Assertions Stage', () => {
  const mockConfig: HardAssertionStageConfig = {
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.2,
      secondaryLabelMinGap: 0.1,
    },
    categorySignals: {
      Financial: {
        hard_assertions: {
          from_domains_ref: {
            source_group: 'banking_domains',
            confidence: 'high',
          },
          subject_prefixes: ['[ALERT]', '[URGENT]'],
          from_addresses: ['noreply@bank.com'],
        },
      },
      Shopping: {
        hard_assertions: {
          subject_prefixes: ['Order Confirmation'],
        },
      },
    },
    domainLookup: {
      banking_domains: {
        high_confidence: [
          { domain: 'chase.com', type: 'bank' },
          { domain: 'bankofamerica.com', type: 'bank' },
        ],
        medium_confidence: [],
        low_confidence: [],
      },
    },
  };

  const createMockEmail = (overrides: Partial<EmailMessage> = {}): EmailMessage => ({
    id: 'test-email-id',
    threadId: 'test-thread-id',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [],
    },
    subject: 'Test Subject',
    from: { email: 'test@example.com', raw: 'test@example.com' },
    to: [{ email: 'recipient@example.com', raw: 'recipient@example.com' }],
    date: new Date(),
    isProcessed: false,
    processingPriority: 1,
    ...overrides,
  });

  const createMockProcessingConfig = (): ProcessingConfig => ({
    version: '1.0.0',
    confidence_thresholds: mockConfig.confidenceThresholds,
    processing_config: {
      top_level_categories: {},
    },
    domain_groups: {},
    category_signals: mockConfig.categorySignals,
  });

  // Helper to set up test with initial category scores
  const setupTest = (initialScores: Record<string, number> = {}) => {
    const processingConfig = createMockProcessingConfig();
    const session = createClassificationSession(processingConfig);
    const email = createMockEmail();
    const result = createClassificationResult(email.id, session.id);

    // Initialize scores
    for (const [category, score] of Object.entries(initialScores)) {
      result.scoreBreakdown.categoryScores[category] = {
        baseScore: score,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: score,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };
    }

    return { email, session, result };
  };

  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('from_domains_ref assertions', () => {
    it('should trigger hard assertion for matching high-confidence domain', () => {
      const { session, result } = setupTest({ Financial: 0.1, Shopping: 0.2 });
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.scoreBreakdown.categoryScores.Financial.finalScore).toBe(0.8); // HIGH_CONFIDENCE_FLOOR
      expect(result.explainabilityTrace.hardAssertions[0]).toMatchObject({
        category: 'Financial',
        triggered: true,
        assertionType: 'from_domain',
        matchedValue: 'chase.com',
        confidence: 'HIGH_CONFIDENCE',
        sourceGroup: 'banking_domains',
      });
    });

    it('should not trigger hard assertion for non-matching domain', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        from: { email: 'user@random.com', raw: 'user@random.com' },
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(0);
      expect(result.scoreBreakdown.categoryScores.Financial.finalScore).toBe(0.1); // Original score unchanged
    });

    it('should preserve existing higher score when hard assertion floor is lower', () => {
      const { session, result } = setupTest({ Financial: 0.9 });
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.scoreBreakdown.categoryScores.Financial.finalScore).toBe(0.9); // Should remain at higher score
      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
    });
  });

  describe('subject_prefixes assertions', () => {
    it('should trigger hard assertion for matching subject prefix', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: '[ALERT] Your account has been compromised',
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.scoreBreakdown.categoryScores.Financial.finalScore).toBe(0.8);
      expect(result.explainabilityTrace.hardAssertions[0]).toMatchObject({
        category: 'Financial',
        triggered: true,
        assertionType: 'subject_prefix',
        matchedValue: '[ALERT]',
        confidence: 'HIGH_CONFIDENCE',
      });
    });

    it('should handle case-insensitive subject prefix matching', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: '[alert] Your account needs attention',
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.explainabilityTrace.hardAssertions[0].matchedValue).toBe('[ALERT]');
    });

    it('should stop at first matching prefix', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        subject: '[ALERT] [URGENT] Critical notification',
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.explainabilityTrace.hardAssertions[0].matchedValue).toBe('[ALERT]'); // First match wins
    });
  });

  describe('from_addresses assertions', () => {
    it('should trigger hard assertion for exact email address match', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        from: { email: 'noreply@bank.com', raw: 'noreply@bank.com' },
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.scoreBreakdown.categoryScores.Financial.finalScore).toBe(0.8);
      expect(result.explainabilityTrace.hardAssertions[0]).toMatchObject({
        category: 'Financial',
        triggered: true,
        assertionType: 'from_address',
        matchedValue: 'noreply@bank.com',
        confidence: 'HIGH_CONFIDENCE',
      });
    });

    it('should handle normalized email comparison', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        from: { email: 'NoReply@Bank.Com', raw: 'NoReply@Bank.Com' },
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.explainabilityTrace.hardAssertions[0].matchedValue).toBe('noreply@bank.com');
    });
  });

  describe('multiple assertions and categories', () => {
    it('should handle multiple assertion types for same category', () => {
      const { session, result } = setupTest({ Financial: 0.1 });
      const email = createMockEmail({
        from: { email: 'user@chase.com', raw: 'user@chase.com' },
        subject: '[ALERT] Account notification',
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(2); // Both domain and subject assertions
      expect(result.scoreBreakdown.categoryScores.Financial.finalScore).toBe(0.8); // Still high confidence floor
    });

    it('should handle assertions across multiple categories', () => {
      const { session, result } = setupTest({ Shopping: 0.2 });
      const email = createMockEmail({
        subject: 'Order Confirmation #12345',
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.scoreBreakdown.categoryScores.Shopping.finalScore).toBe(0.8);
      expect(result.explainabilityTrace.hardAssertions[0].category).toBe('Shopping');
    });

    it('should not affect categories without matching assertions', () => {
      const { session, result } = setupTest({ Financial: 0.1, Shopping: 0.2 });
      const email = createMockEmail({
        subject: 'Random newsletter',
        from: { email: 'newsletter@example.com', raw: 'newsletter@example.com' },
      });
      result.emailId = email.id;

      executeHardAssertions(email, session, result, mockConfig);

      expect(result.explainabilityTrace.hardAssertions).toHaveLength(0);
      expect(result.scoreBreakdown.categoryScores.Financial.finalScore).toBe(0.1); // Original scores preserved
      expect(result.scoreBreakdown.categoryScores.Shopping.finalScore).toBe(0.2);
