        K_low: 2,
        M_medium: 0.8,
        M_low: 0.5,
        TAIL_DAMPEN: 0.5,
        TAIL_RATIO_CAP: 0.3,
      },
    };
  });

  describe('Configuration Validation', () => {
    it('should validate valid configuration successfully', () => {
      const result = RuleScoringStageConfigSchema.safeParse(mockConfig);
      expect(result.success).toBe(true);
    });

    it('should reject invalid tuning parameters', () => {
      const invalidConfig = {
        ...mockConfig,
        tuningParameters: {
          ...mockConfig.tuningParameters,
          K_high: 0, // Invalid - must be >= 1
          M_medium: 1.5, // Invalid - must be <= 1
        },
      };

      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
      expect(result.error?.issues).toHaveLength(2);
    });

    it('should reject unknown rule operations', () => {
      const invalidConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Test',
            subtypes: {
              test: {
                description: 'Test',
                rule_based_classification: {
                  high_confidence: [
                    {
                      field: 'subject',
                      operation: 'invalid_operation' as string,
                      values: ['test'],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
    });
  });

  describe('executeRuleScoring()', () => {
    it('should process emails with rule matches successfully', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.ruleScoring.length).toBeGreaterThan(0);
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBeGreaterThan(0);
      expect(result.explainabilityTrace.stageTimings.rule_scoring).toBeGreaterThanOrEqual(0);
    });

    it('should calculate sophisticated bounded aggregation correctly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult).toBeDefined();
      expect(financialResult!.subtypeScores.receipt).toBeDefined();

      // Should have multiple rule matches with different weights
      const receiptScore = financialResult!.subtypeScores.receipt;
      expect(receiptScore.ruleMatches.length).toBeGreaterThan(1);
      expect(receiptScore.totalScore).toBeGreaterThan(12); // High confidence + medium matches

      // Verify bounded aggregation breakdown
      expect(receiptScore.aggregationBreakdown).toContain(':');
      expect(financialResult!.scoringRationale[0]).toContain('Rule aggregation:');
    });

    it('should handle emails with no rule matches', () => {
      const emptyEmail: EmailMessage = {
        ...mockEmail,
        subject: 'Random subject with no patterns',
        bodyPlain: 'This is just random content with no matching patterns',
        bodyHtml: undefined,
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      executeRuleScoring(emptyEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(0);
    });

    it('should preserve existing scores when rules don\'t improve them', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      // Set high existing score
      result.scoreBreakdown.categoryScores.financial = {
        baseScore: 25.0,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: 25.0,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };

      executeRuleScoring(mockEmail, session, result, mockConfig);

      // Should use max of existing vs rule score
      expect(result.scoreBreakdown.categoryScores.financial.finalScore).toBeGreaterThanOrEqual(25.0);
    });

    it('should handle disabled rule scoring settings', () => {
      const disabledConfig = {
        ...mockConfig,
        settings: {
          use_lexical_patterns: false,
          apply_subtype_rules: false,
          bounded_aggregation: true,
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, disabledConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      // Disabled config should not produce rule scoring results
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(0);
    });

    it('should update context tracking properly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.stageTimings.rule_scoring).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.configurationRefs.rule_scoring).toBe(
        'config.processing_config.top_level_categories.*.subtypes.*.rule_based_classification'
      );
    });

    it('should handle multiple categories with matches', () => {
      const multiCategoryEmail: EmailMessage = {
        ...mockEmail,
        subject: 'TODO: Review receipt for meeting expenses',
        bodyPlain: 'Please review the total amount charged: $50.00',
      };

      const { session, result } = setupTest();
      result.emailId = multiCategoryEmail.id;
      executeRuleScoring(multiCategoryEmail, session, result, mockConfig);

      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(2);
      expect(result.scoreBreakdown.categoryScores.financial?.finalScore).toBeGreaterThan(0);
      expect(result.scoreBreakdown.categoryScores.actionable?.finalScore).toBeGreaterThan(0);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const actionableResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'actionable');

      expect(financialResult?.selectedSubtypeId).toBe('receipt');
      expect(actionableResult?.selectedSubtypeId).toBe('explicit_action');
    });
  });

  describe('Rule Evaluation Functions', () => {
    describe('contains_any operation', () => {
      it('should match any value in the list', () => {
        // Test subject content directly via stage execution
        const testEmail = { ...mockEmail, subject: 'Your receipt is ready' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        expect(financialResult?.ruleMatches.some((match) => match.matchedValue === 'receipt')).toBe(true);
      });

      it('should be case insensitive', () => {
        const testEmail = { ...mockEmail, subject: 'RECEIPT for your order' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        expect(financialResult?.ruleMatches.some((match) => match.operation === 'contains_any')).toBe(true);
      });

      it('should not match when no values are found', () => {
        const testEmail = { ...mockEmail, subject: 'Random subject' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        const subjectMatches =
          financialResult?.ruleMatches.filter(
            (match) => match.field === 'subject' && match.operation === 'contains_any'
          ) || [];
        expect(subjectMatches.length).toBe(0);
      });
    });

    describe('starts_with operation', () => {
      it('should match prefixes correctly', () => {
        const testEmail = { ...mockEmail, subject: 'TODO: Review this document' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const actionableResult = result.explainabilityTrace.ruleScoring.find(
          (cat) => cat.categoryCode === 'actionable'
        );
        expect(
          actionableResult?.ruleMatches.some(
            (match) => match.operation === 'starts_with' && match.matchedValue === 'TODO:'
          )
        ).toBe(true);
      });

      it('should be case insensitive for starts_with', () => {
        const testEmail = { ...mockEmail, subject: 'todo: check this' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const actionableResult = result.explainabilityTrace.ruleScoring.find(
          (cat) => cat.categoryCode === 'actionable'
        );
        expect(actionableResult?.ruleMatches.length).toBeGreaterThan(0);
      });
    });

    describe('regex_any operation', () => {
      it('should match regex patterns correctly', () => {
        const testEmail = { ...mockEmail, bodyPlain: 'The total cost is $129.99' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        const regexMatches = financialResult?.ruleMatches.filter((match) => match.operation === 'regex_any') || [];
        expect(regexMatches.length).toBeGreaterThan(0);
        expect(regexMatches[0].matchedValue).toMatch(/\$\d+\.\d{2}/);
      });

      it('should handle invalid regex gracefully', () => {
        const invalidRegexConfig = {
          ...mockConfig,
          topLevelCategories: {
            test_category: {
              description: 'Test',
              subtypes: {
                test_subtype: {
                  description: 'Test',
                  rule_based_classification: {
                    medium_confidence: [
                      {
                        field: 'body',
                        operation: 'regex_any' as const,
                        values: ['[invalid regex pattern'],
                        weight: 5,
                      },
                    ],
                  },
                },
              },
            },
          },
        };

        // Spy on console.log to check error handling
        const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

        const { session, result } = setupTest();
        result.emailId = mockEmail.id;
        executeRuleScoring(mockEmail, session, result, invalidRegexConfig);

        expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Invalid regex pattern'));
        consoleSpy.mockRestore();
      });
    });

    describe('exists operation', () => {
      it('should match when field has content', () => {
        const existsConfig = {
          ...mockConfig,
          topLevelCategories: {
            test_category: {
              description: 'Test',
              subtypes: {
                has_subject: {
                  description: 'Test',
                  rule_based_classification: {
                    low_confidence: [
                      {
                        field: 'subject',
                        operation: 'exists' as const,
                        values: [],
                        weight: 2,
                      },
                    ],
                  },
                },
              },
            },
          },
        };

        const { session, result } = setupTest();
        result.emailId = mockEmail.id;
        executeRuleScoring(mockEmail, session, result, existsConfig);

        const testResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'test_category');
        expect(testResult?.ruleMatches.some((match) => match.operation === 'exists')).toBe(true);
      });
    });
  });

  describe('Bounded Aggregation Logic', () => {
    it('should apply K_high limit to high confidence matches', () => {
      const multiHighConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Test with many high confidence rules',
                rule_based_classification: {
                  high_confidence: [
                    { field: 'subject', operation: 'contains_any', values: ['receipt'], weight: 12 },
                    { field: 'subject', operation: 'contains_any', values: ['purchase'], weight: 11 },
                    { field: 'subject', operation: 'contains_any', values: ['order'], weight: 10 },
                    { field: 'body', operation: 'contains_any', values: ['total'], weight: 9 },
                  ],
                },
              },
            },
          },
        },
        tuningParameters: {
          ...mockConfig.tuningParameters,
          K_high: 2, // Only top 2 high confidence matches
        },
      };

      const testEmail = {
        ...mockEmail,
        subject: 'Receipt for your purchase order',
        bodyPlain: 'Total amount: $50',
      };

      const { session, result } = setupTest();
      result.emailId = testEmail.id;
      executeRuleScoring(testEmail, session, result, multiHighConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const receiptScore = financialResult?.subtypeScores.receipt;

      // Should only count top K_high=2 matches (12 + 11 = 23)
      const highMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'high_confidence') || [];
      expect(highMatches.length).toBeLessThanOrEqual(2);
    });

    it('should apply multipliers to medium and low confidence tiers', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const receiptScore = financialResult?.subtypeScores.receipt;

      const mediumMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'medium_confidence') || [];
      const lowMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'low_confidence') || [];

      // Verify tiers are properly categorized
      if (mediumMatches.length > 0) {
        expect(mediumMatches[0].tier).toBe('medium_confidence');
      }
      if (lowMatches.length > 0) {
        expect(lowMatches[0].tier).toBe('low_confidence');
      }
    });

    it('should calculate tail support with dampening', () => {
      const multiSubtypeConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Receipt',
                rule_based_classification: {
                  high_confidence: [{ field: 'subject', operation: 'contains_any', values: ['receipt'], weight: 15 }],
                },
              },
              invoice: {
                description: 'Invoice',
                rule_based_classification: {
                  high_confidence: [{ field: 'subject', operation: 'contains_any', values: ['order'], weight: 12 }],
                },
              },
            },
          },
        },
      };

      const testEmail = {
        ...mockEmail,
        subject: 'Receipt for order confirmation',
      };

      const { session, result } = setupTest();
      result.emailId = testEmail.id;
      executeRuleScoring(testEmail, session, result, multiSubtypeConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.scoringRationale[0]).toContain('primary:');

      // Should have both receipt and invoice subtypes with scores
      expect(Object.keys(financialResult?.subtypeScores || {})).toContain('receipt');
      expect(Object.keys(financialResult?.subtypeScores || {})).toContain('invoice');
    });
  });

  describe('Confidence Calculation', () => {
    it('should calculate confidence based on score and match count', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.confidence).toBeGreaterThan(0);
      expect(financialResult?.confidence).toBeLessThanOrEqual(95); // Capped at 95%
    });

    it('should return 0 confidence for zero scores', () => {
      const emptyEmail = {
        ...mockEmail,
        subject: 'No matching patterns',
        bodyPlain: 'No matching content',
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      // Start with empty scores
      result.scoreBreakdown.categoryScores = {};

      executeRuleScoring(emptyEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.confidence).toBe(0);
    });
  });

  describe('Subtype Selection', () => {
    it('should select highest scoring subtype', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.selectedSubtypeId).toBe('receipt');
    });

    it('should return null when no subtypes have scores', () => {
      const emptyEmail = {
        ...mockEmail,
        subject: 'No patterns',
        bodyPlain: 'No patterns',
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      executeRuleScoring(emptyEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.selectedSubtypeId).toBeNull();
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle missing subject and body fields', () => {
      const incompleteEmail: EmailMessage = {
        ...mockEmail,
        subject: '', // Empty subject instead of undefined
        bodyPlain: undefined,
        bodyHtml: undefined,
      };

      const { session, result } = setupTest();
      result.emailId = incompleteEmail.id;
      executeRuleScoring(incompleteEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.stageTimings.rule_scoring).toBeGreaterThanOrEqual(0);
    });

    it('should handle empty values arrays in rules', () => {
      const emptyValuesConfig = {
        ...mockConfig,
        topLevelCategories: {
          test_category: {
            description: 'Test',
            subtypes: {
              empty_values: {
                description: 'Test empty values',
                rule_based_classification: {
                  high_confidence: [
                    {
                      field: 'subject',
                      operation: 'contains_any' as const,
                      values: [],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, emptyValuesConfig);

      // Should handle gracefully without errors
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should handle subtypes without rule_based_classification', () => {
      const noRulesConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              no_rules: {
                description: 'Subtype without rules',
                // No rule_based_classification
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, noRulesConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should handle unknown rule fields gracefully', () => {
      const unknownFieldConfig = {
        ...mockConfig,
        topLevelCategories: {
          test_category: {
            description: 'Test',
            subtypes: {
              unknown_field: {
                description: 'Test unknown field',
                rule_based_classification: {
                  high_confidence: [
                    {
                      field: 'unknown_field',
                      operation: 'contains_any' as const,
                      values: ['test'],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, unknownFieldConfig);

      // Should not crash, should handle gracefully
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });
  });

  describe('Performance and Explainability', () => {
    it('should complete processing within reasonable time limits', () => {
      const startTime = Date.now();

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(1000); // Should complete in under 1 second
      expect(result.explainabilityTrace.stageTimings.rule_scoring).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.stageTimings.rule_scoring).toBeLessThan(1000);
    });

    it('should provide complete explainability information', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      for (const categoryResult of result.explainabilityTrace.ruleScoring) {
        if (Object.keys(categoryResult.subtypeScores).length > 0) {
          expect(categoryResult.scoringRationale.length).toBeGreaterThan(0);
          expect(categoryResult.ruleMatches).toBeDefined();

          for (const match of categoryResult.ruleMatches) {
            expect(match.field).toBeDefined();
            expect(match.operation).toBeDefined();
            expect(match.tier).toBeDefined();
            expect(match.matchedValue).toBeDefined();
            expect(match.ruleId).toBeDefined();
            expect(match.weight).toBeGreaterThan(0);
          }
        }
      }
    });

    it('should generate consistent results across multiple runs', () => {
      const { session: session1, result: result1 } = setupTest();
      result1.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session1, result1, mockConfig);

      const { session: session2, result: result2 } = setupTest();
      result2.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session2, result2, mockConfig);

      // Compare score breakdowns
      expect(result1.scoreBreakdown.categoryScores).toEqual(result2.scoreBreakdown.categoryScores);
      // Compare explainability traces
      expect(result1.explainabilityTrace.ruleScoring).toEqual(result2.explainabilityTrace.ruleScoring);
    });
  });

  describe('Integration with Classification Pipeline', () => {
    it('should preserve result structure correctly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      executeRuleScoring(mockEmail, session, result, mockConfig);

      // Should populate result with proper structure
      expect(result.scoreBreakdown.categoryScores).toBeDefined();
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should work with empty initial category scores', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      // Start with empty scores
      result.scoreBreakdown.categoryScores = {};

      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.categoryScores).toBeDefined();
      expect(Object.keys(result.scoreBreakdown.categoryScores).length).toBeGreaterThan(0);
    });

    it('should handle large configuration files efficiently', () => {
      // Create a config with many categories and rules
      const largeConfig = {
        ...mockConfig,
        topLevelCategories: {},
      };

      // Generate 10 categories with 5 subtypes each
      for (let i = 0; i < 10; i++) {
        const categoryName = `category_${i}`;
        (largeConfig.topLevelCategories as Record<string, TopLevelCategory>)[categoryName] = {
          description: `Category ${i}`,
          subtypes: {},
          ai_final_classification: {
            category_description: `AI classification for category ${i}`,
            decision_criteria: [`Criteria for category ${i}`],
          },
        };

        for (let j = 0; j < 5; j++) {
          const subtypeName = `subtype_${i}_${j}`;
          (largeConfig.topLevelCategories as Record<string, TopLevelCategory>)[categoryName].subtypes[subtypeName] = {
            description: `Subtype ${i} ${j}`,
            rule_based_classification: {
              high_confidence: [
                {
                  field: 'subject',
                  operation: 'contains_any',
                  values: [`pattern_${i}_${j}`],
                  weight: 10,
                },
              ],
            },
          };
        }
      }

      const startTime = Date.now();

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, largeConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(2000); // Should handle large configs efficiently
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });
  });
});

